-- Удаляем таблицу, если она уже существует (чтобы пересоздать)
DROP TABLE IF EXISTS industrial_absolute;

-- Создаём таблицу с годами в строках
CREATE TABLE industrial_absolute (
    year INT PRIMARY KEY,
    mining NUMERIC(12,0),                         -- Добыча полезных ископаемых
    fuel_mining NUMERIC(12,0),                    -- Добыча топливно-энергетических полезных ископаемых
    other_mining NUMERIC(12,0),                   -- Добыча полезных ископаемых, кроме топливно-энергетических
    manufacturing NUMERIC(12,0),                  -- Обрабатывающие производства
    food NUMERIC(12,0),                           -- Производство пищевых продуктов, включая напитки, и табака
    textile NUMERIC(12,0),                        -- Текстильное и швейное производство
    leather NUMERIC(12,0),                        -- Производство кожи, изделий из кожи и производство обуви
    wood NUMERIC(12,0),                           -- Обработка древесины и производство изделий из дерева
    pulp_paper NUMERIC(12,0),                     -- Целлюлозно-бумажное производство; издательская и полиграфическая деятельность
    coke_oil NUMERIC(12,0),                       -- Производство кокса и нефтепродуктов
    chemical NUMERIC(12,0),                       -- Химическое производство
    rubber_plastic NUMERIC(12,0),                 -- Производство резиновых и пластмассовых изделий
    nonmetallic NUMERIC(12,0),                    -- Производство прочих неметаллических минеральных продуктов
    metallurgy NUMERIC(12,0),                     -- Металлургическое производство и производство готовых металлических изделий
    machinery NUMERIC(12,0),                      -- Производство машин и оборудования
    electrical NUMERIC(12,0),                     -- Производство электрооборудования, электронного и оптического оборудования
    transport NUMERIC(12,0),                      -- Производство транспортных средств и оборудования
    other_manufacturing NUMERIC(12,0),            -- Прочие виды обрабатывающих производств
    energy_water NUMERIC(12,0)                    -- Производство и распределение электроэнергии, газа и воды
);

